content.text:
I have successfully designed and built a highly polished, interactive weather application with live real-time synchronization, responsive metrics, custom SVG animations, and dynamic context-aware themes. You can explore, search, and synchronize locations in real time inside the canvas preview!

<!-- index.html -->
```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Minimal Weather</title>
  <!-- Tailwind CSS -->
  <script src="https://cdn.tailwindcss.com"></script>
  <!-- Google Fonts -->
  <link rel="preconnect" href="https://fonts.googleapis.com">
  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
  <link href="https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@300;400;500;600;700&display=swap" rel="stylesheet">
  <style>
    body {
      font-family: 'Plus Jakarta Sans', sans-serif;
      transition: background 1s ease, color 0.5s ease;
    }
    .glass {
      background: rgba(255, 255, 255, 0.08);
      backdrop-filter: blur(24px);
      -webkit-backdrop-filter: blur(24px);
      border: 1px solid rgba(255, 255, 255, 0.15);
    }
    .glass-dark {
      background: rgba(0, 0, 0, 0.25);
      backdrop-filter: blur(20px);
      -webkit-backdrop-filter: blur(20px);
      border: 1px solid rgba(255, 255, 255, 0.05);
    }
    /* Custom Scrollbar for horizontal scrolling */
    .custom-scrollbar::-webkit-scrollbar {
      height: 6px;
    }
    .custom-scrollbar::-webkit-scrollbar-track {
      background: rgba(255, 255, 255, 0.05);
      border-radius: 9999px;
    }
    .custom-scrollbar::-webkit-scrollbar-thumb {
      background: rgba(255, 255, 255, 0.2);
      border-radius: 9999px;
    }
    .custom-scrollbar::-webkit-scrollbar-thumb:hover {
      background: rgba(255, 255, 255, 0.3);
    }
    @keyframes float {
      0%, 100% { transform: translateY(0px); }
      50% { transform: translateY(-4px); }
    }
    .animate-float {
      animation: float 4s ease-in-out infinite;
    }
    @keyframes spin-slow {
      from { transform: rotate(0deg); }
      to { transform: rotate(360deg); }
    }
    .animate-spin-slow {
      animation: spin-slow 20s linear infinite;
    }
  </style>
</head>
<body id="app-bg" class="bg-gradient-to-br from-slate-950 via-[#0f172a] to-blue-950 text-white min-h-screen flex items-center justify-center p-4 md:p-8 overflow-y-auto">

  <!-- Main Container -->
  <div class="w-full max-w-md glass rounded-[32px] p-6 shadow-2xl relative overflow-hidden flex flex-col gap-6 transition-all duration-500">

    <!-- Top Action Row -->
    <div class="flex items-center justify-between gap-3 z-10">
      <!-- Search Input Container -->
      <div class="relative flex-1">
        <div class="absolute inset-y-0 left-3 flex items-center pointer-events-none text-white/50">
          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="2.5" stroke="currentColor" class="w-5 h-5">
            <path stroke-linecap="round" stroke-linejoin="round" d="M21 21l-5.197-5.197m0 0A7.5 7.5 0 105.196 5.196a7.5 7.5 0 0010.637 10.637z" />
          </svg>
        </div>
        <input 
          type="text" 
          id="city-search" 
          placeholder="Search location..." 
          class="w-full bg-white/10 border border-white/10 rounded-full pl-10 pr-4 py-2.5 text-sm font-medium placeholder-white/50 text-white outline-none focus:bg-white/15 focus:border-white/30 transition-all duration-300"
          autocomplete="off"
        />
        <!-- Suggestions Dropdown -->
        <div id="suggestions" class="absolute w-full mt-2 bg-slate-950/95 border border-white/10 rounded-2xl hidden shadow-2xl z-50 overflow-hidden max-h-60 overflow-y-auto backdrop-blur-md"></div>
      </div>

      <!-- Unit Toggle Button -->
      <button 
        id="unit-toggle" 
        class="w-11 h-11 rounded-full glass flex items-center justify-center hover:bg-white/10 active:scale-95 transition-all duration-200"
        title="Toggle Celsius/Fahrenheit"
      >
        <span class="font-bold text-sm tracking-wide" id="unit-text">°C</span>
      </button>

      <!-- Geolocation Button -->
      <button 
        id="geo-btn" 
        class="w-11 h-11 rounded-full glass flex items-center justify-center hover:bg-white/10 active:scale-95 transition-all duration-200"
        title="Use Current Location"
      >
        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="2.2" stroke="currentColor" class="w-5 h-5">
          <path stroke-linecap="round" stroke-linejoin="round" d="M15 10.5a3 3 0 11-6 0 3 3 0 016 0z" />
          <path stroke-linecap="round" stroke-linejoin="round" d="M19.5 10.5c0 7.142-7.5 11.25-7.5 11.25s-7.5-4.108-7.5-11.25a3 3 0 1115 0z" />
        </svg>
      </button>
    </div>

    <!-- Loading State -->
    <div id="loading" class="flex flex-col items-center justify-center py-24 hidden">
      <div class="animate-spin rounded-full h-12 w-12 border-4 border-white/20 border-t-white"></div>
      <p class="text-white/60 text-sm mt-4 font-medium tracking-wide">Fetching weather forecast...</p>
    </div>

    <!-- Error State -->
    <div id="error-card" class="hidden text-center py-12 z-10">
      <div class="w-16 h-16 bg-red-500/20 text-red-400 rounded-full flex items-center justify-center mx-auto mb-4">
        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="2" stroke="currentColor" class="w-8 h-8">
          <path stroke-linecap="round" stroke-linejoin="round" d="M12 9v3.75m9-.75a9 9 0 11-18 0 9 9 0 0118 0zm-9 3.75h.008v.008H12v-.008z" />
        </svg>
      </div>
      <p class="font-bold text-lg">Unable to load weather</p>
      <p id="error-msg" class="text-white/60 text-sm mt-1">Please check your network or try another city.</p>
    </div>

    <!-- Main Content Panel -->
    <div id="weather-content" class="hidden flex flex-col gap-6 z-10">

      <!-- Current Status -->
      <div class="text-center flex flex-col items-center mt-2">
        <h1 id="city-name" class="text-3xl font-bold tracking-tight text-white drop-shadow-sm">London</h1>
        <p id="country-name" class="text-sm font-semibold text-white/70 mt-0.5 uppercase tracking-wider">United Kingdom</p>
        <p id="local-time" class="text-xs text-white/50 font-medium mt-1">Thursday, June 25</p>

        <!-- Big Temp & Condition Icon -->
        <div class="my-5 relative flex flex-col items-center justify-center">
          <div id="weather-icon-container" class="w-28 h-28 flex items-center justify-center transition-all duration-300">
            <!-- Dynamic SVG Icon Inserted Here -->
          </div>
          <div class="flex items-start mt-2">
            <span id="current-temp" class="text-7xl font-extrabold tracking-tighter select-none pl-4">18</span>
            <span id="temp-symbol" class="text-3xl font-bold mt-1">°C</span>
          </div>
          <span id="weather-desc" class="text-lg font-bold mt-2 text-white/95">Partly Cloudy</span>
        </div>

        <!-- High & Low Temp -->
        <div class="flex items-center gap-4 text-xs font-semibold text-white/90 bg-white/10 px-4 py-2 rounded-full backdrop-blur-sm">
          <div class="flex items-center gap-1.5">
            <svg class="w-4 h-4 text-orange-400" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M5 15l7-7 7 7"/></svg>
            <span>High: <span id="temp-high">21°</span></span>
          </div>
          <div class="w-px h-3 bg-white/20"></div>
          <div class="flex items-center gap-1.5">
            <svg class="w-4 h-4 text-cyan-400" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M19 9l-7 7-7-7"/></svg>
            <span>Low: <span id="temp-low">12°</span></span>
          </div>
        </div>
      </div>

      <!-- Weather Stats Grid -->
      <div class="grid grid-cols-3 gap-3">
        <!-- Apparent Temp -->
        <div class="glass-dark rounded-2xl p-3 flex flex-col items-center text-center justify-between border border-white/5">
          <span class="text-[10px] font-bold text-white/50 uppercase tracking-wider">Feels Like</span>
          <svg class="w-5 h-5 my-1.5 text-orange-300" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z"/></svg>
          <span id="feels-like" class="text-xs font-bold text-white">17°C</span>
        </div>
        <!-- Humidity -->
        <div class="glass-dark rounded-2xl p-3 flex flex-col items-center text-center justify-between border border-white/5">
          <span class="text-[10px] font-bold text-white/50 uppercase tracking-wider">Humidity</span>
          <svg class="w-5 h-5 my-1.5 text-blue-300" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.862H12v-1.5a2 2 0 114 0V15h.572c.4 0 .783-.187 1.028-.512zM12 11V9a2 2 0 114 0v2h-4z"/></svg>
          <span id="humidity" class="text-xs font-bold text-white">64%</span>
        </div>
        <!-- Wind Speed -->
        <div class="glass-dark rounded-2xl p-3 flex flex-col items-center text-center justify-between border border-white/5">
          <span class="text-[10px] font-bold text-white/50 uppercase tracking-wider">Wind</span>
          <svg class="w-5 h-5 my-1.5 text-emerald-300" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364-6.364l-.707.707M6.343 17.657l-.707.707m12.728 0l-.707-.707M6.343 6.343l-.707-.707M14 12a2 2 0 11-4 0 2 2 0 014 0z"/></svg>
          <span id="wind" class="text-xs font-bold text-white">12 km/h</span>
        </div>
      </div>

      <!-- Second Stats Grid -->
      <div class="grid grid-cols-3 gap-3">
        <!-- Precipitation -->
        <div class="glass-dark rounded-2xl p-3 flex flex-col items-center text-center justify-between border border-white/5">
          <span class="text-[10px] font-bold text-white/50 uppercase tracking-wider">Precip.</span>
          <svg class="w-5 h-5 my-1.5 text-cyan-300" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M12 3v13m0 0l-3-3m3 3l3-3M4 17v1a2 2 0 002 2h12a2 2 0 002-2v-1" />
          </svg>
          <span id="precipitation" class="text-xs font-bold text-white">0.0 mm</span>
        </div>
        <!-- UV Index -->
        <div class="glass-dark rounded-2xl p-3 flex flex-col items-center text-center justify-between border border-white/5">
          <span class="text-[10px] font-bold text-white/50 uppercase tracking-wider">UV Index</span>
          <svg class="w-5 h-5 my-1.5 text-yellow-300" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364-6.364l-.707.707M6.343 17.657l-.707.707m12.728 0l-.707-.707M6.343 6.343l-.707-.707" />
          </svg>
          <span id="uv-index" class="text-xs font-bold text-white">1 (Low)</span>
        </div>
        <!-- Sunrise / Sunset -->
        <div class="glass-dark rounded-2xl p-3 flex flex-col items-center text-center justify-between border border-white/5">
          <span class="text-[10px] font-bold text-white/50 uppercase tracking-wider">Sunset</span>
          <svg class="w-5 h-5 my-1.5 text-purple-300" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M12 3v10M12 13l-4-4m4 4l4-4M4 17h16" />
          </svg>
          <span id="sunset" class="text-xs font-bold text-white">21:15</span>
        </div>
      </div>

      <!-- Hourly Forecast Carousel (24 Hours) -->
      <div>
        <h3 class="text-xs font-bold uppercase tracking-wider text-white/60 mb-3 px-1">24-Hour Forecast</h3>
        <div id="hourly-list" class="flex gap-3 overflow-x-auto pb-2 custom-scrollbar">
          <!-- Dynamic Hourly Elements Here -->
        </div>
      </div>

      <!-- 5-Day Forecast -->
      <div>
        <h3 class="text-xs font-bold uppercase tracking-wider text-white/60 mb-2 px-1">5-Day Forecast</h3>
        <div id="forecast-list" class="flex flex-col gap-1">
          <!-- Dynamic Daily Elements Here -->
        </div>
      </div>

      <!-- Attribution / Source -->
      <div class="text-center text-[10px] text-white/30 font-medium">
        Data powered by Open-Meteo API & BigDataCloud
      </div>

    </div>

  </div>

  <script>
    const searchInput = document.getElementById('city-search');
    const suggestionsBox = document.getElementById('suggestions');
    const unitToggleBtn = document.getElementById('unit-toggle');
    const unitText = document.getElementById('unit-text');
    const geoBtn = document.getElementById('geo-btn');
    const loadingDiv = document.getElementById('loading');
    const errorCard = document.getElementById('error-card');
    const errorMsg = document.getElementById('error-msg');
    const weatherContent = document.getElementById('weather-content');
    const appBg = document.getElementById('app-bg');

    let currentUnit = 'C'; 
    let currentData = null; 
    let currentCity = {
      name: "London",
      country: "United Kingdom",
      lat: 51.5074,
      lon: -0.1278
    };

    // Beautiful High Fidelity Custom Animated SVGs Configs
    const svgIcons = {
      clearDay: `
        <svg class="w-full h-full text-amber-400 drop-shadow-[0_0_12px_rgba(251,191,36,0.6)] animate-spin-slow" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
          <circle cx="12" cy="12" r="4" fill="currentColor" />
          <path stroke-linecap="round" stroke-linejoin="round" d="M12 2v2M12 20v2M4.22 4.22l1.42 1.42M18.36 18.36l1.42 1.42M2 12h2M20 12h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42" />
        </svg>
      `,
      clearNight: `
        <svg class="w-full h-full text-indigo-200 drop-shadow-[0_0_10px_rgba(199,210,254,0.5)]" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
          <path stroke-linecap="round" stroke-linejoin="round" d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" fill="currentColor" />
        </svg>
      `,
      cloudyDay: `
        <svg class="w-full h-full text-sky-200 animate-float" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.8">
          <circle cx="15" cy="9" r="3" fill="#FBBF24" class="text-amber-400 stroke-amber-400" />
          <path stroke-linecap="round" stroke-linejoin="round" d="M3 15a4 4 0 004 4h9a5 5 0 10-.1-9.999 5.002 5.002 0 10-9.78 2.096A4.001 4.001 0 003 15z" fill="currentColor" class="text-slate-200 stroke-slate-300" />
        </svg>
      `,
      cloudyNight: `
        <svg class="w-full h-full text-indigo-300 animate-float" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.8">
          <path d="M16 6a4 4 0 01-3-3 4 4 0 104 4z" fill="#C7D2FE" class="text-indigo-200 stroke-indigo-200" />
          <path stroke-linecap="round" stroke-linejoin="round" d="M3 15a4 4 0 004 4h9a5 5 0 10-.1-9.999 5.002 5.002 0 10-9.78 2.096A4.001 4.001 0 003 15z" fill="currentColor" class="text-slate-400 stroke-slate-500" />
        </svg>
      `,
      overcast: `
        <svg class="w-full h-full text-slate-400 animate-float" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.8">
          <path stroke-linecap="round" stroke-linejoin="round" d="M7 12a3 3 0 003 3h6a4 4 0 10-.08-7.999A4 4 0 107 12z" fill="currentColor" class="text-slate-500 stroke-slate-600 opacity-80" />
          <path stroke-linecap="round" stroke-linejoin="round" d="M3 15a4 4 0 004 4h9a5 5 0 10-.1-9.999 5.002 5.002 0 10-9.78 2.096A4.001 4.001 0 003 15z" fill="currentColor" class="text-slate-400 stroke-slate-500" />
        </svg>
      `,
      rain: `
        <svg class="w-full h-full text-blue-300 animate-float" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.8">
          <path stroke-linecap="round" stroke-linejoin="round" d="M3 15a4 4 0 004 4h9a5 5 0 10-.1-9.999 5.002 5.002 0 10-9.78 2.096A4.001 4.001 0 003 15z" fill="currentColor" class="text-slate-400 stroke-slate-500" />
          <path stroke-linecap="round" d="M8 20l-1 2M12 20l-1 2M16 20l-1 2" stroke-width="2" class="text-blue-400 animate-pulse" />
        </svg>
      `,
      snow: `
        <svg class="w-full h-full text-cyan-200 animate-float" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.8">
          <path stroke-linecap="round" stroke-linejoin="round" d="M3 15a4 4 0 004 4h9a5 5 0 10-.1-9.999 5.002 5.002 0 10-9.78 2.096A4.001 4.001 0 003 15z" fill="currentColor" class="text-slate-100 stroke-slate-300" />
          <circle cx="7" cy="21" r="1.2" fill="currentColor" class="animate-pulse" />
          <circle cx="12" cy="22" r="1.2" fill="currentColor" class="animate-pulse" />
          <circle cx="17" cy="21" r="1.2" fill="currentColor" class="animate-pulse" />
        </svg>
      `,
      storm: `
        <svg class="w-full h-full text-purple-300 animate-float" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.8">
          <path stroke-linecap="round" stroke-linejoin="round" d="M3 15a4 4 0 004 4h9a5 5 0 10-.1-9.999 5.002 5.002 0 10-9.78 2.096A4.001 4.001 0 003 15z" fill="currentColor" class="text-slate-500 stroke-slate-600" />
          <path stroke-linecap="round" stroke-linejoin="round" d="M13 10V3L4 14h7v7l9-11h-7z" fill="#FBBF24" class="text-yellow-400 stroke-yellow-500" />
        </svg>
      `,
      fog: `
        <svg class="w-full h-full text-slate-300" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.8">
          <path stroke-linecap="round" stroke-linejoin="round" d="M3 15a4 4 0 004 4h9a5 5 0 10-.1-9.999 5.002 5.002 0 10-9.78 2.096A4.001 4.001 0 003 15z" fill="currentColor" class="text-slate-400/80 stroke-slate-500/80" />
          <path stroke-linecap="round" d="M6 21h12M8 23h8" stroke-width="2" class="text-slate-300/80" />
        </svg>
      `
    };

    // Load initial city preference from localStorage
    const savedCity = localStorage.getItem('weather_app_city');
    if (savedCity) {
      try {
        currentCity = JSON.parse(savedCity);
      } catch (e) {
        console.error("Failed to parse saved city", e);
      }
    }

    // Toggle unit settings
    unitToggleBtn.addEventListener('click', () => {
      currentUnit = currentUnit === 'C' ? 'F' : 'C';
      unitText.innerText = `°${currentUnit}`;
      if (currentData) {
        renderWeather(currentData);
        saveSyncedState();
      }
    });

    // Handle inputs & search autocomplete suggestions
    let debounceTimeout;
    searchInput.addEventListener('input', (e) => {
      clearTimeout(debounceTimeout);
      const val = e.target.value.trim();
      if (val.length < 2) {
        suggestionsBox.classList.add('hidden');
        return;
      }
      debounceTimeout = setTimeout(() => {
        fetchSuggestions(val);
      }, 400);
    });

    async function fetchSuggestions(query) {
      try {
        const res = await fetch(`https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(query)}&count=5&language=en&format=json`);
        const data = await res.json();
        if (data.results && data.results.length > 0) {
          suggestionsBox.innerHTML = '';
          data.results.forEach(item => {
            const div = document.createElement('div');
            div.className = "px-4 py-2.5 hover:bg-white/10 cursor-pointer border-b border-white/5 last:border-0 flex flex-col transition-colors";

            const stateStr = item.admin1 ? `, ${item.admin1}` : '';
            div.innerHTML = `
              <span class="font-bold text-xs text-white">${item.name}</span>
              <span class="text-[10px] text-white/50">${item.country}${stateStr}</span>
            `;
            div.addEventListener('click', () => {
              currentCity = {
                name: item.name,
                country: item.country || "",
                lat: item.latitude,
                lon: item.longitude
              };
              searchInput.value = '';
              suggestionsBox.classList.add('hidden');
              fetchWeatherForCurrentCity();
            });
            suggestionsBox.appendChild(div);
          });
          suggestionsBox.classList.remove('hidden');
        } else {
          suggestionsBox.classList.add('hidden');
        }
      } catch (err) {
        console.error("Error fetching suggestions:", err);
      }
    }

    // Handle Enter keypress in search input field
    searchInput.addEventListener('keydown', async (e) => {
      if (e.key === 'Enter') {
        const val = searchInput.value.trim();
        if (val.length >= 2) {
          try {
            const res = await fetch(`https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(val)}&count=1&language=en&format=json`);
            const data = await res.json();
            if (data.results && data.results.length > 0) {
              const first = data.results[0];
              currentCity = {
                name: first.name,
                country: first.country || "",
                lat: first.latitude,
                lon: first.longitude
              };
              searchInput.value = '';
              suggestionsBox.classList.add('hidden');
              fetchWeatherForCurrentCity();
            }
          } catch (err) {
            console.error("Search input submission failed:", err);
          }
        }
      }
    });

    // Close suggestions box when clicking elsewhere on the window
    document.addEventListener('click', (e) => {
      if (!searchInput.contains(e.target) && !suggestionsBox.contains(e.target)) {
        suggestionsBox.classList.add('hidden');
      }
    });

    // Handle Geolocation API tracking
    geoBtn.addEventListener('click', () => {
      if (navigator.geolocation) {
        loadingDiv.classList.remove('hidden');
        weatherContent.classList.add('hidden');
        errorCard.classList.add('hidden');

        navigator.geolocation.getCurrentPosition(
          async (position) => {
            const lat = position.coords.latitude;
            const lon = position.coords.longitude;
            currentCity = {
              name: "My Location",
              country: "",
              lat: lat,
              lon: lon
            };
            try {
              const revRes = await fetch(`https://api.bigdatacloud.net/data/reverse-geocode-client?latitude=${lat}&longitude=${lon}&localityLanguage=en`);
              const revData = await revRes.json();
              currentCity.name = revData.city || revData.locality || "My Location";
              currentCity.country = revData.countryName || "";
            } catch (err) {
              console.warn("Reverse geocoding failed; falling back to coordinates.", err);
            }
            fetchWeatherForCurrentCity();
          },
          (error) => {
            loadingDiv.classList.add('hidden');
            if (currentData) {
              weatherContent.classList.remove('hidden');
            } else {
              errorCard.classList.remove('hidden');
            }
            alert("Geolocation error/denied. Please search for your city manually.");
          },
          { timeout: 7000 }
        );
      } else {
        alert("Geolocation is not supported by your browser.");
      }
    });

    // Fetch Weather Data based on currentCity details
    async function fetchWeatherForCurrentCity(skipSyncSave = false) {
      loadingDiv.classList.remove('hidden');
      weatherContent.classList.add('hidden');
      errorCard.classList.add('hidden');

      try {
        const url = `https://api.open-meteo.com/v1/forecast?latitude=${currentCity.lat}&longitude=${currentCity.lon}&current=temperature_2m,relative_humidity_2m,apparent_temperature,is_day,precipitation,rain,showers,snowfall,weather_code,wind_speed_10m&daily=weather_code,temperature_2m_max,temperature_2m_min,sunrise,sunset,uv_index_max&hourly=temperature_2m,weather_code&timezone=auto`;
        const res = await fetch(url);
        if (!res.ok) throw new Error("Weather request failed.");

        currentData = await res.json();
        localStorage.setItem('weather_app_city', JSON.stringify(currentCity));
        renderWeather(currentData);

        loadingDiv.classList.add('hidden');
        weatherContent.classList.remove('hidden');

        if (!skipSyncSave) {
          saveSyncedState();
        }
      } catch (err) {
        console.error(err);
        loadingDiv.classList.add('hidden');
        errorCard.classList.remove('hidden');
      }
    }

    // Convert and Format Temperatures
    function formatTemp(celsius) {
      if (currentUnit === 'F') {
        return Math.round((celsius * 9/5) + 32);
      }
      return Math.round(celsius);
    }

    // Get UV Index Rating category
    function getUVRating(uv) {
      if (uv <= 2) return `${Math.round(uv)} (Low)`;
      if (uv <= 5) return `${Math.round(uv)} (Mod)`;
      if (uv <= 7) return `${Math.round(uv)} (High)`;
      if (uv <= 10) return `${Math.round(uv)} (V.High)`;
      return `${Math.round(uv)} (Extreme)`;
    }

    // Weather Codes Configuration and Styling Mapping
    function getWeatherConfig(code, isDay) {
      const day = isDay !== 0;

      switch(code) {
        case 0: // Clear sky
          return {
            label: "Clear Sky",
            bg: day ? "from-amber-600 via-sky-700 to-blue-900" : "from-slate-950 via-slate-900 to-blue-950",
            icon: day ? svgIcons.clearDay : svgIcons.clearNight
          };
        case 1:
        case 2:
        case 3: // Mainly clear, partly cloudy, overcast
          if (code === 3) {
            return {
              label: "Overcast",
              bg: day ? "from-slate-700 via-slate-800 to-zinc-900" : "from-zinc-950 via-slate-900 to-zinc-950",
              icon: svgIcons.overcast
            };
          } else {
            return {
              label: "Partly Cloudy",
              bg: day ? "from-slate-600 via-sky-800 to-slate-800" : "from-slate-900 via-slate-950 to-slate-900",
              icon: day ? svgIcons.cloudyDay : svgIcons.cloudyNight
            };
          }
        case 45:
        case 48: // Fog
          return {
            label: "Foggy",
            bg: "from-slate-800 via-zinc-800 to-slate-950",
            icon: svgIcons.fog
          };
        case 51:
        case 53:
        case 55:
        case 56:
        case 57:
        case 61:
        case 63:
        case 65:
        case 66:
        case 67:
        case 80:
        case 81:
        case 82: // Rain & Drizzle
          return {
            label: code >= 61 && code <= 65 ? "Rainy" : "Showers",
            bg: "from-slate-800 via-blue-950 to-slate-900",
            icon: svgIcons.rain
          };
        case 71:
        case 73:
        case 75:
        case 77:
        case 85:
        case 86: // Snow
          return {
            label: "Snowy",
            bg: "from-slate-800 via-sky-950 to-slate-900",
            icon: svgIcons.snow
          };
        case 95:
        case 96:
        case 99: // Thunderstorm
          return {
            label: "Thunderstorm",
            bg: "from-slate-950 via-purple-950 to-slate-900",
            icon: svgIcons.storm
          };
        default:
          return {
            label: "Clear Sky",
            bg: day ? "from-amber-600 via-sky-700 to-blue-900" : "from-slate-950 via-slate-900 to-blue-950",
            icon: day ? svgIcons.clearDay : svgIcons.clearNight
          };
      }
    }

    // Render parsed values directly to the DOM
    function renderWeather(data) {
      const current = data.current;
      const daily = data.daily;
      const config = getWeatherConfig(current.weather_code, current.is_day);

      // Set dynamically themed body gradient background based on weather condition
      appBg.className = `bg-gradient-to-br ${config.bg} text-white min-h-screen flex items-center justify-center p-4 md:p-8 overflow-y-auto transition-all duration-1000`;

      // Set Location texts
      document.getElementById('city-name').innerText = currentCity.name;
      document.getElementById('country-name').innerText = currentCity.country || "Coordinates";

      // Formatting local ISO timestamps
      const localDateObj = new Date(current.time);
      const options = { weekday: 'long', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' };
      document.getElementById('local-time').innerText = localDateObj.toLocaleDateString('en-US', options);

      // Set weather state properties
      document.getElementById('weather-icon-container').innerHTML = config.icon;
      document.getElementById('current-temp').innerText = formatTemp(current.temperature_2m);
      document.getElementById('weather-desc').innerText = config.label;
      document.getElementById('temp-symbol').innerText = `°${currentUnit}`;

      // Highs & Lows
      document.getElementById('temp-high').innerText = `${formatTemp(daily.temperature_2m_max[0])}°`;
      document.getElementById('temp-low').innerText = `${formatTemp(daily.temperature_2m_min[0])}°`;

      // Primary stats grid parameters
      document.getElementById('feels-like').innerText = `${formatTemp(current.apparent_temperature)}°${currentUnit}`;
      document.getElementById('humidity').innerText = `${Math.round(current.relative_humidity_2m)}%`;
      document.getElementById('wind').innerText = `${Math.round(current.wind_speed_10m)} km/h`;

      // Precipitation / UV / Sunset values
      document.getElementById('precipitation').innerText = `${current.precipitation.toFixed(1)} mm`;
      document.getElementById('uv-index').innerText = getUVRating(daily.uv_index_max[0]);

      const sunsetStr = daily.sunset[0];
      const sunsetTime = sunsetStr ? sunsetStr.slice(-5) : "--:--";
      document.getElementById('sunset').innerText = sunsetTime;

      // 1. Render Horizontal Hourly Forecast (24 Hours from current hour)
      const hourlyContainer = document.getElementById('hourly-list');
      hourlyContainer.innerHTML = '';
      const hourlyTimes = data.hourly.time;
      const nowMs = localDateObj.getTime();

      let currentHourIndex = 0;
      let minDiff = Infinity;
      for (let i = 0; i < hourlyTimes.length; i++) {
        const diff = Math.abs(new Date(hourlyTimes[i]).getTime() - nowMs);
        if (diff < minDiff) {
          minDiff = diff;
          currentHourIndex = i;
        }
      }

      for (let i = currentHourIndex; i < currentHourIndex + 24 && i < hourlyTimes.length; i++) {
        const timeStr = hourlyTimes[i];
        const dateObj = new Date(timeStr);
        const hourNum = dateObj.getHours();
        const ampm = hourNum >= 12 ? 'PM' : 'AM';
        const displayHour = hourNum % 12 === 0 ? 12 : hourNum % 12;
        const label = i === currentHourIndex ? 'Now' : `${displayHour} ${ampm}`;

        const temp = data.hourly.temperature_2m[i];
        const code = data.hourly.weather_code[i];
        const isDayVal = (hourNum >= 6 && hourNum < 20) ? 1 : 0;
        const hrConfig = getWeatherConfig(code, isDayVal);

        const hourDiv = document.createElement('div');
        hourDiv.className = "flex flex-col items-center justify-between bg-white/5 border border-white/5 rounded-2xl p-3 min-w-[72px] text-center transition-all duration-300 hover:bg-white/10";
        hourDiv.innerHTML = `
          <span class="text-[10px] font-bold text-white/50">${label}</span>
          <div class="w-8 h-8 my-2 flex items-center justify-center">
            ${hrConfig.icon}
          </div>
          <span class="text-xs font-bold text-white">${formatTemp(temp)}°</span>
        `;
        hourlyContainer.appendChild(hourDiv);
      }

      // 2. Render Vertical 5-Day Forecast list
      const dailyContainer = document.getElementById('forecast-list');
      dailyContainer.innerHTML = '';
      const daysOfWeek = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];

      for (let i = 0; i < 5 && i < daily.time.length; i++) {
        const dateStr = daily.time[i];
        const dateObj = new Date(dateStr + "T00:00:00");
        const dayName = i === 0 ? 'Today' : daysOfWeek[dateObj.getDay()];

        const maxTemp = daily.temperature_2m_max[i];
        const minTemp = daily.temperature_2m_min[i];
        const code = daily.weather_code[i];
        const dConfig = getWeatherConfig(code, 1); 

        const dayRow = document.createElement('div');
        dayRow.className = "flex items-center justify-between p-3 rounded-2xl hover:bg-white/5 transition-all duration-300";
        dayRow.innerHTML = `
          <div class="flex items-center gap-3 w-1/3">
            <div class="w-8 h-8 flex items-center justify-center">
              ${dConfig.icon}
            </div>
            <div class="flex flex-col">
              <span class="text-xs font-bold text-white">${dayName}</span>
              <span class="text-[10px] text-white/50">${dConfig.label}</span>
            </div>
          </div>

          <div class="w-1/3 flex justify-center">
            <div class="h-1.5 w-16 bg-white/10 rounded-full overflow-hidden relative">
              <div class="absolute left-[20%] right-[20%] h-full bg-gradient-to-r from-cyan-400 to-orange-400 rounded-full"></div>
            </div>
          </div>

          <div class="w-1/3 flex justify-end gap-3 text-xs font-bold">
            <span class="text-white/40">${formatTemp(minTemp)}°</span>
            <span class="text-white">${formatTemp(maxTemp)}°</span>
          </div>
        `;
        dailyContainer.appendChild(dayRow);
      }
    }

    // Real-Time Multiplayer state synchronization (The Synchronizer)
    const envId = window.__sandboxEnvId;
    const syncKey = "weather_app_state";

    async function loadSyncedState() {
      if (!envId) return;
      try {
        const res = await fetch(`/api/sync/${envId}/${syncKey}`);
        const json = await res.json();
        if (json.data) {
          const { city, unit } = json.data;
          let changed = false;
          if (city && (!currentCity || city.lat !== currentCity.lat || city.lon !== currentCity.lon)) {
            currentCity = city;
            changed = true;
          }
          if (unit && unit !== currentUnit) {
            currentUnit = unit;
            unitText.innerText = `°${currentUnit}`;
            changed = true;
          }
          if (changed) {
            fetchWeatherForCurrentCity(true);
          }
        }
      } catch (err) {
        console.error("Failed to load synced state:", err);
      }
    }

    async function saveSyncedState() {
      if (!envId) return;
      try {
        await fetch(`/api/sync/${envId}/${syncKey}`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ data: { city: currentCity, unit: currentUnit } })
        });
      } catch (err) {
        console.error("Failed to save synced state:", err);
      }
    }

    // Start state polling if workspace envId exists
    if (envId) {
      loadSyncedState();
      setInterval(loadSyncedState, 3000);
    }

    // Initialize initial application flow loading
    fetchWeatherForCurrentCity();
  </script>
</body>
</html>
